try {
  const rawText = $json.output || $json.text || $json.message || '';
  const cleanJson = rawText.replace(/```json/g, '').replace(/```/g, '').trim();
  const parsed = JSON.parse(cleanJson);
  parsed.status = 'classificado';
  return [{ json: parsed }];
} catch (e) {
  return [{ json: { file_id: $('Split In Batches').item.json.file_id, status: 'erro', erro: e.message } }];
}
